import { useEffect, useState } from "react";
import { getCart } from "../api/api";

function Cart() {
  const [cart, setCart] = useState(null);

  useEffect(() => {
    loadCart();
  }, []);

  async function loadCart() {
    const data = await getCart(1);
    setCart(data);
  }

  if (!cart) return <p>Laddar...</p>;

  return (
    <div>
      <h1>Varukorg</h1>

      {cart.items.length === 0 && (
        <p>Varukorgen är tom</p>
      )}

      {cart.items.map((item, index) => (
        <div key={index}>
          <p>
            {item.name} - {item.price} kr - {item.amount} st - {item.price * item.amount} kr
          </p>
        </div>
      ))}

      <h3>Total: {cart.totalPrice} kr</h3>
    </div>
  );
}

export default Cart;
